#include <chrono>
#include <cstdio>
#include <iostream>
#include <cub/cub.cuh>

// Preconditions and Postconditions:
// - Preconditions:
//   1) d_in and d_out are 16-byte aligned device pointers (true for cudaMalloc).
//   2) num_items is rounded up to a multiple of items_per_block (= BLOCK_THREADS * 4).
//   3) grid.x * blockDim.x == num_items / 4, so each thread processes exactly 4 contiguous ints.
// - Postconditions:
//   For each block b and for each element i in [0, items_per_block):
//     d_out[b*items_per_block + i] = (i == 0) ? d_in[b*items_per_block + i]
//                                            : d_in[b*items_per_block + i] - d_in[b*items_per_block + i - 1]
//
// Loop invariants (host reference computation):
// - For each block b processed in order, and for each i processed within that block:
//   Invariant I1: out[i] is computed only from in[i] and in[i-1] that belong to the same block segment.
//   Invariant I2: The base pointer 'in' = h_in + b * items_per_block and 'out' = r_out + b * items_per_block
//                 remain constant across the inner loop over i.
//   Preservation: Advancing i to i+1 preserves I1 and I2 since both refer to the same block-scoped arrays,
//                 and (i+1)-1 == i is still within the same block-scoped segment.
//   Initialization: At i=0, the conditional handles the left boundary as defined.
//   Termination: After i reaches items_per_block, all elements in the block segment satisfy the postcondition.
//
// Kernel semantic equivalence:
// - Each thread t loads 4 contiguous ints from d_in at indices [4*tid, 4*tid+1, 4*tid+2, 4*tid+3] via int4,
//   participates in cub::BlockAdjacentDifference::SubtractLeft across the block, and stores the 4 results.
// - The block-wide CUB primitive guarantees that for every thread element j>0 within the block-wide linearization,
//   the left neighbor used for the difference is exactly the previous element in that linear order; j==0 uses identity.
// - This matches the host reference per-block computation, thus preserving correctness by construction.

struct CustomDifference
{
  template <typename DataType>
  __device__ __forceinline__ DataType operator()(const DataType &lhs, const DataType &rhs) const
  {
    return lhs - rhs;
  }
};

template <int BLOCK_THREADS>
__launch_bounds__(BLOCK_THREADS)
__global__ void BlockAdjDiffKernel(const int* __restrict__ d_in, int* __restrict__ d_out)
{
  constexpr int ITEMS_PER_THREAD = 4;

  using BlockAdjacentDifferenceT = cub::BlockAdjacentDifference<int, BLOCK_THREADS>;

  __shared__ typename BlockAdjacentDifferenceT::TempStorage temp_storage;

  const int idx = blockIdx.x * blockDim.x + threadIdx.x;

  // Vectorized, coalesced read via read-only path to reduce LG/MIO stalls (PC refs: stall_lg_ratio, stall_mio_ratio).
  const int4* __restrict__ in4  = reinterpret_cast<const int4*>(d_in);
  int4* __restrict__ out4 = reinterpret_cast<int4*>(d_out);

  int thread_data[ITEMS_PER_THREAD];
  int4 v = __ldg(in4 + idx);
  reinterpret_cast<int4*>(thread_data)[0] = v;

  // Block-wide adjacent difference; CUB manages shared memory/barriers.
  BlockAdjacentDifferenceT(temp_storage).SubtractLeft(
      thread_data,
      thread_data,
      CustomDifference());

  // Vectorized, coalesced store.
  out4[idx] = reinterpret_cast<int4*>(thread_data)[0];
}

void Initialize(int* h_in, int num_items)
{
  for (int i = 0; i < num_items; ++i)
  {
    h_in[i] = i % 17;
  }
}

template <int BLOCK_THREADS>
void Test(int num_items, int repeat)
{
  const int ITEMS_PER_THREAD = 4;
  const int items_per_block = BLOCK_THREADS * ITEMS_PER_THREAD;

  // Round up to full blocks of 4 items/thread to avoid partial tiles and ensure aligned int4 accesses.
  num_items = ((num_items + items_per_block - 1) / items_per_block) * items_per_block;

  int* h_in = new int[num_items];
  int* h_out = new int[num_items];
  int* r_out = new int[num_items];

  Initialize(h_in, num_items);

  int* d_in  = nullptr;
  int* d_out = nullptr;
  cudaMalloc((void**) &d_in, sizeof(int) * num_items);
  cudaMalloc((void**) &d_out, sizeof(int) * num_items);

  const int grid_size = num_items / items_per_block;

  dim3 grid (grid_size);
  dim3 block (BLOCK_THREADS);

  cudaMemcpy(d_in, h_in, sizeof(int) * num_items, cudaMemcpyHostToDevice);

  // Prefer shared memory as CUB uses it heavily; helps reduce barrier/IMC contention on H100.
  cudaFuncSetCacheConfig(BlockAdjDiffKernel<BLOCK_THREADS>, cudaFuncCachePreferShared);

  for (int i = 0; i < repeat; i++) {
    BlockAdjDiffKernel<BLOCK_THREADS><<<grid, block>>>(d_in, d_out);
  }
  cudaMemcpy(h_out, d_out, sizeof(int) * num_items, cudaMemcpyDeviceToHost);

  // Reference computation with explicit invariants noted above.
  for (int b = 0; b < grid_size; b++) {
    auto in = h_in + b * items_per_block;
    auto out = r_out + b * items_per_block;
    for (int i = 0; i < items_per_block; i++) {
      out[i] = (i - 1) < 0 ? in[i] : in[i] - in[i-1];
    }
  }

  int compare = memcmp(r_out, h_out, sizeof(int) * num_items);
  printf("%s\n", compare ? "FAIL" : "PASS");

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    BlockAdjDiffKernel<BLOCK_THREADS><<<grid, block>>>(d_in, d_out);
  }

  cudaDeviceSynchronize();
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average execution time of the kernel: %f (us)\n", (time * 1e-3f) / repeat);

  if (h_in) delete[] h_in;
  if (h_out) delete[] h_out;
  if (r_out) delete[] r_out;
  if (d_in) cudaFree(d_in);
  if (d_out) cudaFree(d_out);
}

int main(int argc, char** argv)
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int nelems = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  Test<  64>(nelems, repeat);
  Test< 128>(nelems, repeat);
  Test< 256>(nelems, repeat);
  Test< 512>(nelems, repeat);
  Test<1024>(nelems, repeat);

  return 0;
}
