double sobolGPU(int repeat, int n_vectors, int n_dimensions,
                unsigned int *d_directions, float *d_output);

#endif // SOBOL_GPU_H

#include "sobol.h"
#include "sobol_gpu.h"

#include <chrono>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <iostream>
#include <vector>
#include <cassert>

#define k_2powneg32 2.3283064E-10F

// Preconditions (mathematical):
// - n_vectors >= 0, n_dimensions >= 1.
// - d_directions points to an array with at least n_dimensions * 32 valid unsigned ints,
//   where the 32 entries for each dimension are the Sobol direction numbers for that dimension.
// - d_output points to an array with at least n_dimensions * n_vectors floats.
// - Grid setup uses dimGrid.y == n_dimensions; blockIdx.y selects the dimension.
// Postconditions:
// - For each dimension d in [0, n_dimensions), and each index i in [0, n_vectors),
//   d_output[d*n_vectors + i] = Sobol_float(i, d) where Sobol_float(i, d) is computed from
//   32-bit direction numbers for dimension d, scaled by 2^-32.
//
// Loop invariants and correctness notes appear inline below.

#ifndef CUDA_CHECK
#define CUDA_CHECK(call) do { \
  cudaError_t _e = (call); \
  if (_e != cudaSuccess) { \
    fprintf(stderr, "CUDA error %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(_e)); \
    std::exit(EXIT_FAILURE); \
  } \
} while(0)
#endif

// We keep the original kernel name and signature.
// Structural optimizations:
// - Use __launch_bounds__(256) to guide register allocation/occupancy on H100.
// - Stage direction numbers for the chosen dimension once into shared memory, then
//   copy them into per-thread registers to avoid repeated shared memory traffic.
// - Increase threads per block to 256 (host code) to raise achieved occupancy.
// - Reduce repeated calls to __ffs by hoisting to locals.
// - Use __ldg when loading direction numbers to utilize read-only cache.
static __device__ __forceinline__ unsigned ldg_u32(const unsigned* ptr) {
#if __CUDA_ARCH__ >= 350
  return __ldg(ptr);
#else
  return *ptr;
#endif
}

constexpr int kSobolDirections = 32;

__global__ __launch_bounds__(256)
void sobolGPU_kernel(unsigned n_vectors, unsigned n_dimensions,
                     unsigned *__restrict__ d_directions,
                     float *__restrict__ d_output)
{
  // Preconditions (assertions for development; no runtime effect in release):
  // - blockIdx.y < n_dimensions (guaranteed by launch configuration).
  // - d_directions has at least n_dimensions * kSobolDirections entries.
  // - d_output has at least n_dimensions * n_vectors entries.

  // Shared memory staging of direction numbers for this dimension.
  __shared__ unsigned sv[kSobolDirections];

  // Compute per-dimension base pointers.
  const unsigned dim = blockIdx.y;
  const unsigned* __restrict__ dir_base = (const unsigned* __restrict__)d_directions + dim * kSobolDirections;
  float* __restrict__ out_base = d_output + dim * n_vectors;

  // Cooperative load of direction numbers into shared memory.
  if (threadIdx.x < kSobolDirections) {
    sv[threadIdx.x] = ldg_u32(&dir_base[threadIdx.x]);
  }

  __syncthreads();

  // Copy once into per-thread registers to avoid further shared-memory dependence.
  // Loop invariant (copy phase):
  //   After copying index t (0 <= t < kSobolDirections), vreg[j] == sv[j] for all j <= t,
  //   and remains uninitialized for j > t. This invariant ensures equivalence to reading
  //   sv[j] later inside computational loops.
  unsigned vreg[kSobolDirections];
#pragma unroll
  for (int t = 0; t < kSobolDirections; ++t) {
    vreg[t] = sv[t];
  }

  const unsigned i0     = threadIdx.x + blockIdx.x * blockDim.x;
  const unsigned stride = gridDim.x * blockDim.x;

  // Hoist __ffs(stride); stride is power-of-two multiple of blockDim.x by host setup.
  const unsigned ffs_stride = __ffs(stride);      // 1-based bit index of LS1B
  const unsigned ffs_m1     = ffs_stride - 1;     // number of trailing zeros in stride

  // Gray code for index i0.
  unsigned g = i0 ^ (i0 >> 1);

  // Compute first output X for i0 using direction numbers corresponding to set bits in Gray code g.
  // Loop invariant (first loop over k):
  //   At the start of iteration k (0-based), X equals XOR over all j < k of
  //   ( (g_initial >> j) & 1 ? vreg[j] : 0 ), and current g == g_initial >> k.
  //   This ensures at loop end (k == ffs_m1), X equals XOR over j in [0, ffs_m1)
  //   where bit j of initial Grey code is 1, matching original semantics.
  unsigned X = 0;
#pragma unroll
  for (unsigned k = 0; k < ffs_m1; ++k) {
    const unsigned mask = -(g & 1u);
    X ^= (mask & vreg[k]);
    g >>= 1;
  }

  if (i0 < n_vectors) {
    out_base[i0] = (float)X * k_2powneg32;
  }

  // Precompute constants for the grid-stride progression.
  // v_log2stridem1 corresponds to direction number at (log2(stride) - 1).
  // Invariant: stride is a multiple of 64, hence ffs_stride >= 7 and index is valid.
  const unsigned v_log2stridem1 = vreg[ffs_stride - 2];
  const unsigned v_stridemask   = stride - 1;

  // Grid-stride loop:
  // Loop invariant (i-loop):
  //   Before writing out_base[i], X equals Sobol_int(i - stride) for this dimension.
  //   We update X ^= v_log2stridem1 ^ vreg[idx], where
  //     idx = __ffs(~((i - stride) | v_stridemask)) - 1,
  //   which flips exactly the changed Gray code bit between successive indices advanced by 'stride'.
  //   Therefore X becomes Sobol_int(i). This invariant preserves the correctness of sequence progression.
  for (unsigned i = i0 + stride; i < n_vectors; i += stride) {
    const unsigned idx = __ffs(~((i - stride) | v_stridemask)) - 1;
    X ^= (v_log2stridem1 ^ vreg[idx]);
    out_base[i] = (float)X * k_2powneg32;
  }

  // Postconditions:
  // - For each processed i, out_base[i] holds the correct Sobol float computed from X scaled by 2^-32.
  // - No shared state is modified beyond sv[], and all threads observe identical sv[] contents.
}

double sobolGPU(int repeat, int n_vectors, int n_dimensions,
                unsigned int *d_directions, float *d_output)
{
  // Tuned threads-per-block for H100 occupancy and latency hiding (see analysis refs [1][2]).
  const int threadsperblock = 256;

  dim3 dimGrid;
  dim3 dimBlock;

  // 1D grid in X for vectors, Y for dimensions.
  dimGrid.y = n_dimensions;

  // Seed a target grid.x to keep enough blocks resident (heuristic).
  if (n_dimensions < (4 * 24)) {
    dimGrid.x = 4 * 24;
  } else {
    dimGrid.x = 1;
  }

  // Respect vector count.
  if (dimGrid.x > (unsigned int)(n_vectors / threadsperblock)) {
    dimGrid.x = (n_vectors + threadsperblock - 1) / threadsperblock;
  }

  // Round up to next power of two for stride-friendly math in kernel.
  unsigned int targetDimGridX = dimGrid.x;
  for (dimGrid.x = 1; dimGrid.x < targetDimGridX; dimGrid.x <<= 1) { }

  dimBlock.x = threadsperblock;

  CUDA_CHECK(cudaDeviceSynchronize());
  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    sobolGPU_kernel<<<dimGrid, dimBlock>>>(n_vectors, n_dimensions, d_directions, d_output);
  }

  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaDeviceSynchronize());
  auto end = std::chrono::steady_clock::now();
  double time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  return time;
}

// A minimal main demonstrating usage.
int main(int argc, char** argv) {
  int n_vectors    = (argc > 1) ? std::atoi(argv[1]) : (1 << 20);
  int n_dimensions = (argc > 2) ? std::atoi(argv[2]) : 64;
  int repeat       = (argc > 3) ? std::atoi(argv[3]) : 10;

  assert(n_vectors >= 0);
  assert(n_dimensions >= 1);

  // Host buffers
  std::vector<unsigned int> h_dirs((size_t)n_dimensions * kSobolDirections);
  std::vector<float> h_out((size_t)n_dimensions * (size_t)n_vectors, 0.0f);

  // Initialize direction numbers (placeholder initialization; in practice, use proper Sobol direction tables).
  for (int d = 0; d < n_dimensions; ++d) {
    for (int k = 0; k < kSobolDirections; ++k) {
      // Ensure non-zero, upper-triangular style; this is not a canonical Sobol set but suffices for a functional run.
      h_dirs[d * kSobolDirections + k] = (1u << (31 - k)) ^ (0x9E3779B9u * (d + 1));
    }
  }

  // Device buffers
  unsigned int* d_dirs = nullptr;
  float* d_out = nullptr;

  size_t sz_dirs = h_dirs.size() * sizeof(unsigned int);
  size_t sz_out  = h_out.size() * sizeof(float);

  CUDA_CHECK(cudaMalloc(&d_dirs, sz_dirs));
  CUDA_CHECK(cudaMalloc(&d_out,  sz_out));
  CUDA_CHECK(cudaMemcpy(d_dirs, h_dirs.data(), sz_dirs, cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemset(d_out, 0, sz_out));

  double ns = sobolGPU(repeat, n_vectors, n_dimensions, d_dirs, d_out);
  std::cout << "Elapsed (avg over " << repeat << "): " << (ns / repeat) * 1e-6 << " ms\n";

  // Copy back a small sample to prevent dead-code elimination and for sanity check.
  CUDA_CHECK(cudaMemcpy(h_out.data(), d_out, std::min((size_t)1024, (size_t)h_out.size()) * sizeof(float), cudaMemcpyDeviceToHost));
  std::cout << "Sample outputs: ";
  for (int i = 0; i < 8 && i < n_vectors; ++i) {
    std::cout << h_out[i] << " ";
  }
  std::cout << "\n";

  CUDA_CHECK(cudaFree(d_dirs));
  CUDA_CHECK(cudaFree(d_out));
  return 0;
}
